SELECT date, total_positive_cases, test_conducted
FROM case_data
ORDER BY date DESC;

SELECT district_name 
FROM districts 
ORDER BY district_name;

SELECT SUM(total_positive_cases) AS total_positive_cases
FROM case_data
WHERE date = (SELECT MAX(date) FROM case_data);

SELECT SUM(total_tests) AS total_tests_conducted
FROM tests_conducted
WHERE district_id = 1;
